// -*- coding: utf-8 -*-
#include <iostream>
#include <vector>
#include <sstream>
using namespace std;
class Solution {
public:
	bool push(int value, int* arr, int& topIndex) {
		if (topIndex < size_limit) {
			arr[topIndex] = value;
			topIndex++;
			return true;
		} else {
			return false;
		}
	}
	bool pop(int* arr, int& topIndex) {
		if (topIndex > 0) {
			arr[topIndex - 1] = arr[topIndex];
			topIndex--;
			return true;
		} else {
			return false;
		}
	}
	int main() {
		size_limit = 0;
		cin>>size_limit;
		int n;
		cin>>n;
		int topIndex = 0;
		int arr[10000];
		for (int i = 0; i < n; ++i) {
			string operation;
			getline(cin, operation);
			istringstream iss(operation);
			string op;
			iss>>op;
			if (op == "push") {
				int value;
				iss>>value;
				if (push(value, arr, topIndex)) {
					cout << value << endl;
				} else {
					cout << -1 << endl;
				}
			} else if (op == "pop") {
				if (topIndex > 0) {
					int value = arr[topIndex - 1];
					topIndex--;
					cout << value << endl;
				} else {
					cout << -1 << endl;
				}
			}
		}
		return 0;
	}
};
